Javascript.isEnabled:
var jurisdiction = Services.getValue("/ds/var/page/CaseJurisdiction");
var blnEnabled = true;
if ( jurisdiction == 'C' || jurisdiction == 'Q') { blnEnabled = false; }
return blnEnabled;

Javascript.logic:
var jurisdiction = Services.getValue("/ds/var/page/CaseJurisdiction");
var sealMessage = "Please note that an electronic seal will automatically be applied to this document prior to printing. Please therefore check that all information is correct before selecting to print this document.";
if ( jurisdiction == 'C' || jurisdiction == 'Q') { sealMessage = ""; }
Services.setValue(SealMessage.dataBinding, sealMessage);
